def balanced(s):
    """Return True if parentheses are balanced, False otherwise."""
    stack = []
    for char in s:
        if char == '(':
            stack.append(char)
        elif char == ')':
            if not stack:
                return False  # edge case: no matching opening parenthesis
            stack.pop()
    return not stack  # empty stack means all parentheses were balanced
